-- db/migrations/014_content_restructure.sql
--
-- Migration 014: course content restructure into 3 groups / 9 sections /
-- per-question answer fields (specs/004-content-restructure).
--
-- See specs/004-content-restructure/contracts/migration-014.md for the contract
-- this migration implements and specs/004-content-restructure/contracts/group-section-mapping.md
-- for the authoritative content mapping.
--
-- DESTRUCTIVE: wipes public.responses and public.progress. Pre-production-safe
-- per Assumption A-1 (user confirmation 2026-05-15).
--
-- Idempotent: re-running produces zero diff (schema guards + delete-then-insert).

BEGIN;

-- ── Phase A — Schema additions ───────────────────────────────────────────
ALTER TABLE public.sections
  ADD COLUMN IF NOT EXISTS group_slug text;

DO $$ BEGIN
  ALTER TABLE public.sections
    ADD CONSTRAINT sections_group_slug_check
    CHECK (group_slug IS NULL
        OR group_slug IN ('self-awareness','goal-setting','strategic-planning'));
EXCEPTION WHEN duplicate_object THEN NULL;
END $$;

COMMENT ON COLUMN public.sections.group_slug IS
  '3-value enum: self-awareness | goal-setting | strategic-planning. Drives the group bands on /course.';

-- ── Phase B — Wipe participant rows ──────────────────────────────────────
DELETE FROM public.responses;
DELETE FROM public.progress;

-- ── Phase C — Reseed sections + exercises ────────────────────────────────
DELETE FROM public.exercises;
DELETE FROM public.sections;

INSERT INTO public.sections (slug, title, subtitle, description, order_index, group_slug, icon_name, framing) VALUES
  ('personality', 'Personality', NULL, NULL, 1, 'self-awareness', NULL, $json${"opening_quote": {"text": "Until you make the unconscious conscious, it will direct your life and you will call it fate.", "attribution": "— Carl Jung"}, "opening_question": "If we asked the five people closest to you to describe how you make decisions, would they all give the same answer?", "facilitator_says": "D.I.S.C. isn't a label — it's a mirror. Today we're going to look at how you naturally show up, before we look at how you choose to show up.", "why_it_matters": "Strategy starts with self-knowledge. You can't plan a life you don't understand. Your D.I.S.C. style shapes how you make decisions, who energises you, and what kind of work feels effortless. Knowing it doesn't lock you in — it gives you a starting point.", "closing_reflection": "What is one D.I.S.C. trait that helps you, and one that gets in your way?", "bridge_to_next": "Knowing your style is one filter. Now we look at the lenses you see through it: your attitudes.", "reading_material": {"title": "How To Read and Understand People — Bill Bonnstetter (TTI)", "content": "A short primer on the D.I.S.C. behavioural model — the framework underneath this section. Bonnstetter explains why the four primary styles (Dominance, Influence, Steadiness, Compliance) are observable patterns, not fixed labels, and how each one tends to make decisions, communicate, and react under pressure. The PSP workshop adapts this work with permission."}}$json$::jsonb),
  ('attitude', 'Attitude', NULL, NULL, 2, 'self-awareness', NULL, $json${"opening_quote": {"text": "Between stimulus and response there is a space. In that space is our power to choose our response.", "attribution": "— Viktor Frankl"}, "opening_question": "What is one belief you hold about yourself that you have never actually questioned?", "facilitator_says": "Attitudes are the lenses we look through. We rarely notice them — but they shape every decision we make.", "why_it_matters": "Even with the right personality and the right skills, the wrong attitude will sabotage you. The good news: attitudes can be examined, named, and chosen. We're going to surface yours so you can decide which to keep, which to soften, and which to retire.", "closing_reflection": "Which one attitude — if you changed it tomorrow — would change the most about your life?", "bridge_to_next": "Attitudes are HOW you see. Values are WHAT you protect. Let's go there next.", "reading_material": {"title": "Man's Search for Meaning — Viktor Frankl", "content": "The book the opening quote comes from. Frankl, a psychiatrist who survived the Nazi camps, argues that meaning is not given to us — it is the response we choose to whatever we are handed. For this section, the relevant move is his: you cannot always change the stimulus, but the space between stimulus and response is where your attitude lives. Naming that space is the first step in this exercise."}}$json$::jsonb),
  ('values', 'Values', NULL, NULL, 3, 'self-awareness', NULL, $json${"opening_quote": {"text": "It's not hard to make decisions when you know what your values are.", "attribution": "— Roy Disney"}, "opening_question": "If you had to give up everything you own except five things — and not material things, but five values — what would you protect?", "facilitator_says": "Values aren't what we say we believe. They are what we spend on — time, energy, attention. Today we make that visible.", "why_it_matters": "Your values are your compass. The Goal Setting section later in this course only works if you have named which direction is north. Most people inherit their values from family, school, or workplace and never audit them. The Values Shopping Spree exercise is your audit.", "closing_reflection": "Which of your top five values is currently underfed?", "bridge_to_next": "You know your style, your lenses, your compass. Now: what hats are you actually wearing day-to-day?", "reading_material": {"title": "The 7 Habits of Highly Effective People — Stephen R. Covey", "content": "Covey's framework treats values as the centre of a personal mission and warns about the cost of confusing values with urgencies. Habit 2 — Begin with the end in mind — is the lens to bring into the Shopping Spree exercise: you are not buying what feels nice today, you are buying the things that, ten years from now, you would still defend as worth the money. Covey also separates principles (universal) from values (chosen) — useful vocabulary if you find the exercise hard."}}$json$::jsonb),
  ('roles-and-demands', 'Roles and Demands', NULL, NULL, 4, 'self-awareness', NULL, $json${"opening_quote": {"text": "You can do anything, but not everything.", "attribution": "— David Allen"}, "opening_question": "If someone made a documentary of your last 30 days, how many different characters would you play in it?", "facilitator_says": "We all wear multiple hats. The question isn't whether — it's whether each hat is one we still want to wear, or one we just inherited.", "why_it_matters": "Roles consume your hours. If you don't audit them, they will consume your life. The Life Line and Past Experience Inventory in this section help you see the shape of your time, not just the content of it. That shape is what your goals will have to fit inside.", "closing_reflection": "Which role on your list deserves more time than it currently gets — and which one secretly deserves less?", "bridge_to_next": "Roles are demands on your time. Skills are what travel with you through every role. Let's catalogue them.", "reading_material": {"title": "Essentialism: The Disciplined Pursuit of Less — Greg McKeown", "content": "McKeown's central move is to treat your roles as decisions, not obligations. A role inherited from family, employer, or habit is still a role you renew every day by showing up. The book offers a useful filter — 'if it isn't a clear yes, it's a clear no' — for the Life Line exercise. Read this before deciding which roles to keep on the list and which to retire."}}$json$::jsonb),
  ('transferable-skills', 'Transferable Marketable Skills', NULL, NULL, 5, 'self-awareness', NULL, $json${"opening_quote": {"text": "Your work is going to fill a large part of your life, and the only way to be truly satisfied is to do what you believe is great work.", "attribution": "— Steve Jobs"}, "opening_question": "What is something you do well that other people seem to find difficult?", "facilitator_says": "Skills aren't just job descriptions. They are patterns — and patterns travel with you wherever you go.", "why_it_matters": "Knowing your transferable skills means you are never trapped in one role. They are leverage. They are the answer to 'what could I do if I had to start over tomorrow?' Strategy needs options, and your skills inventory is your option set.", "closing_reflection": "Which skill, if developed, would unlock the most doors for you next year?", "bridge_to_next": "You have your style, lenses, compass, hats, and toolkit. Now we put it all together — into goals.", "reading_material": {"title": "What Color Is Your Parachute? — Richard N. Bolles", "content": "Bolles invented the modern transferable-skills inventory. The book's core exercise — the Flower — separates a skill from the job that taught you the skill, so you can carry it into completely different work. Read the chapter on transferable skills before the inventory exercise; it will help you list skills as verbs (analyse, listen, organise) rather than as job titles."}}$json$::jsonb),
  ('specific-goals', 'Specific Goals', NULL, NULL, 6, 'goal-setting', NULL, NULL),
  ('goal-impact-matrix', 'Goal Impact Matrix', NULL, NULL, 7, 'goal-setting', NULL, NULL),
  ('visualization', 'Visualization', NULL, NULL, 8, 'goal-setting', NULL, NULL),
  ('removing-obstacles-achieving-goals', 'Removing Obstacles, Achieving Goals', NULL, NULL, 9, 'strategic-planning', NULL, NULL);

-- Exercises — one INSERT per section to keep chunks small.

-- personality
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='personality')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'disc-introduction',
    'D.I.S.C. — Discovering My Personal Behavioural Design',
    'info',
    $json${"content": "The D.I.S.C. MODEL was developed by Bill Bonnstetter at Target Training International, Phoenix, Arizona. It is based on the psychology of Carl Jung and William Moulton Marston and is widely accepted as an effective tool for enhancing performance in all areas of life.\n\nThrough the combined Nature/Nurture process of growing, you have developed specific ways of interacting with the world. This is your Personal Behavioural Style, or CORE STYLE.\n\nThe D.I.S.C. model uses four factors to determine behaviour:\n\n1. THE DOMINANCE FACTOR (D) — How you handle problems and challenges\n2. THE INFLUENCE FACTOR (I) — How you handle people and influence others\n3. THE STEADINESS FACTOR (S) — How you handle and pace yourself\n4. THE COMPLIANCE FACTOR (C) — How you handle the rules set by others\n\nHow you will benefit:\n• Increased Self Understanding\n• Increased Understanding of Others\n• Increased Communication Skills\n• Less Stress\n• Decreased Tension\n• Improved Relationships (Family, Work/Business, Social)", "attribution": "(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)"}$json$::jsonb,
    1,
    false,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'identifying-personal-style',
    'EXERCISE: Identifying Your Own Personal Style',
    'checkbox',
    $json${"prompt": "In the following four categories (D, I, S, C), check which of the statements you tend to agree with more. Rate how strongly (1 to 10) you agree with each statement. Your highest rating indicates your BASIC CORE STYLE.", "options": [{"id": "opt_d", "label": "D — Dominance: You tend to be very active and aggressive in gaining results. You will go directly at the problem with little or no fear. (How you handle problems and challenges)", "value": 1}, {"id": "opt_i", "label": "I — Influence: You usually are very approachable and open to others. Outgoing, social, very verbally persuasive. (How you interact with other people)", "value": 2}, {"id": "opt_s", "label": "S — Steadiness: You prefer a structured and more predictable environment, having the parameters and boundaries clearly defined. Prefer a secure situation. (How you handle a steady pace and your workplace)", "value": 3}, {"id": "opt_c", "label": "C — Compliance: You tend to follow rules set by others and you are very aware of the consequences of not complying with rules or following procedures. (How you respond to rules and procedures imposed by others)", "value": 4}], "allow_multiple": false}$json$::jsonb,
    2,
    true,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'disc-core-style-d',
    'HIGH D — Dominance Core Style Profile',
    'checkbox',
    $json${"prompt": "If you scored highest on D — Dominance, check all the characteristics below that resonate with you. These describe your natural strengths, ideal environment, and tendencies as a HIGH D.", "options": [{"id": "d_char_1", "label": "Able to make decisions quickly", "value": 1}, {"id": "d_char_2", "label": "Willing to state unpopular opinions", "value": 1}, {"id": "d_char_3", "label": "Risk taking", "value": 1}, {"id": "d_env_1", "label": "I thrive with freedom from controls, supervision and details", "value": 1}, {"id": "d_env_2", "label": "I prefer evaluation based on results, not process or method", "value": 1}, {"id": "d_env_3", "label": "I prefer an innovative and futuristic oriented environment", "value": 1}, {"id": "d_env_4", "label": "I prefer non-routine work with challenge and opportunity", "value": 1}, {"id": "d_env_5", "label": "I need a forum to express my ideas and viewpoints", "value": 1}, {"id": "d_trait_1", "label": "Ambitious", "value": 1}, {"id": "d_trait_2", "label": "Forceful", "value": 1}, {"id": "d_trait_3", "label": "Decisive", "value": 1}, {"id": "d_trait_4", "label": "Direct", "value": 1}, {"id": "d_trait_5", "label": "Independent", "value": 1}, {"id": "d_trait_6", "label": "Challenging", "value": 1}, {"id": "d_trait_7", "label": "Results oriented", "value": 1}, {"id": "d_trait_8", "label": "I have a desire to win", "value": 1}, {"id": "d_trait_9", "label": "Argumentative", "value": 1}, {"id": "d_trait_10", "label": "Fast paced", "value": 1}, {"id": "d_trait_11", "label": "I tend to juggle a lot at once", "value": 1}, {"id": "d_trait_12", "label": "I am quick to accept challenge", "value": 1}, {"id": "d_trait_13", "label": "I usually interrupt and am impatient with long explanations", "value": 1}, {"id": "d_trait_14", "label": "I tend to act or speak before thinking", "value": 1}, {"id": "d_trait_15", "label": "I am not afraid of high risk", "value": 1}, {"id": "d_trait_16", "label": "I tend to create fear in others", "value": 1}, {"id": "d_trait_17", "label": "I tend to be impatient", "value": 1}], "allow_multiple": true}$json$::jsonb,
    3,
    true,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'disc-core-style-i',
    'HIGH I — Influence Core Style Profile',
    'checkbox',
    $json${"prompt": "If you scored highest on I — Influence, check all the characteristics below that resonate with you. These describe your natural strengths, ideal environment, and tendencies as a HIGH I.", "options": [{"id": "i_char_1", "label": "A natural optimist", "value": 1}, {"id": "i_char_2", "label": "Trusting of others", "value": 1}, {"id": "i_char_3", "label": "Able to make others feel welcome and/or included", "value": 1}, {"id": "i_env_1", "label": "I thrive with assignments involving a high degree of people contacts", "value": 1}, {"id": "i_env_2", "label": "I enjoy tasks involving motivating groups and establishing a network of contacts", "value": 1}, {"id": "i_env_3", "label": "I prefer a democratic supervisor with whom I can associate", "value": 1}, {"id": "i_env_4", "label": "I need freedom from control and detail", "value": 1}, {"id": "i_env_5", "label": "I need freedom of movement", "value": 1}, {"id": "i_env_6", "label": "I prefer multi-changing work tasks", "value": 1}, {"id": "i_trait_1", "label": "Expressive", "value": 1}, {"id": "i_trait_2", "label": "Enthusiastic", "value": 1}, {"id": "i_trait_3", "label": "Friendly", "value": 1}, {"id": "i_trait_4", "label": "Demonstrative", "value": 1}, {"id": "i_trait_5", "label": "Talkative", "value": 1}, {"id": "i_trait_6", "label": "Stimulating", "value": 1}, {"id": "i_trait_7", "label": "I have a good sense of humor", "value": 1}, {"id": "i_trait_8", "label": "I treat everyone as a friend", "value": 1}, {"id": "i_trait_9", "label": "I am fun loving", "value": 1}, {"id": "i_trait_10", "label": "I am a creative problem solver", "value": 1}, {"id": "i_trait_11", "label": "I am usually very optimistic", "value": 1}, {"id": "i_trait_12", "label": "I tend to talk before thinking", "value": 1}, {"id": "i_trait_13", "label": "I very often lose track of time", "value": 1}, {"id": "i_trait_14", "label": "I prefer to back away from conflict", "value": 1}, {"id": "i_trait_15", "label": "I tend to be disorganized", "value": 1}, {"id": "i_trait_16", "label": "I am very trusting of others", "value": 1}], "allow_multiple": true}$json$::jsonb,
    4,
    true,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'disc-core-style-s',
    'HIGH S — Steadiness Core Style Profile',
    'checkbox',
    $json${"prompt": "If you scored highest on S — Steadiness, check all the characteristics below that resonate with you. These describe your natural strengths, ideal environment, and tendencies as a HIGH S.", "options": [{"id": "s_char_1", "label": "A tenacity for order", "value": 1}, {"id": "s_char_2", "label": "A natural ability to organize tasks", "value": 1}, {"id": "s_env_1", "label": "I thrive in jobs where standards and methods are established", "value": 1}, {"id": "s_env_2", "label": "I prefer environments where long-standing relationships can be developed", "value": 1}, {"id": "s_env_3", "label": "I need personal attention and recognition for tasks completed and well done", "value": 1}, {"id": "s_env_4", "label": "I prefer a stable and predictable environment", "value": 1}, {"id": "s_env_5", "label": "I need environments that allow time for change", "value": 1}, {"id": "s_env_6", "label": "I prefer environments where I can deal with people on a personal, intimate basis", "value": 1}, {"id": "s_trait_1", "label": "Methodical", "value": 1}, {"id": "s_trait_2", "label": "Systematic", "value": 1}, {"id": "s_trait_3", "label": "Reliable", "value": 1}, {"id": "s_trait_4", "label": "Steady", "value": 1}, {"id": "s_trait_5", "label": "Relaxed", "value": 1}, {"id": "s_trait_6", "label": "Modest", "value": 1}, {"id": "s_trait_7", "label": "I need secure situations", "value": 1}, {"id": "s_trait_8", "label": "I'm a good planner", "value": 1}, {"id": "s_trait_9", "label": "I need closure", "value": 1}, {"id": "s_trait_10", "label": "I'm a great listener", "value": 1}, {"id": "s_trait_11", "label": "I am usually calm and stabilize others", "value": 1}, {"id": "s_trait_12", "label": "I mask my emotions", "value": 1}, {"id": "s_trait_13", "label": "I tend to be indirect to avoid conflict", "value": 1}, {"id": "s_trait_14", "label": "I tend to be possessive of things", "value": 1}, {"id": "s_trait_15", "label": "I tend to be too low risk", "value": 1}, {"id": "s_trait_16", "label": "I tend to hold a grudge", "value": 1}, {"id": "s_trait_17", "label": "I tend to adapt very quickly to others", "value": 1}, {"id": "s_trait_18", "label": "I tend to resist changes", "value": 1}], "allow_multiple": true}$json$::jsonb,
    5,
    true,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'disc-core-style-c',
    'HIGH C — Compliance Core Style Profile',
    'checkbox',
    $json${"prompt": "If you scored highest on C — Compliance, check all the characteristics below that resonate with you. These describe your natural strengths, ideal environment, and tendencies as a HIGH C.", "options": [{"id": "c_char_1", "label": "A natural systems developer", "value": 1}, {"id": "c_char_2", "label": "A good quality control person", "value": 1}, {"id": "c_char_3", "label": "Willing to dig for information", "value": 1}, {"id": "c_env_1", "label": "I thrive where critical thinking is needed and rewarded", "value": 1}, {"id": "c_env_2", "label": "I prefer assignments that can be followed through to completion", "value": 1}, {"id": "c_env_3", "label": "I prefer technical, task-oriented, specialized work", "value": 1}, {"id": "c_env_4", "label": "I prefer environments where noise and people are at a minimum", "value": 1}, {"id": "c_env_5", "label": "I prefer close relationships with a small group of people", "value": 1}, {"id": "c_env_6", "label": "I thrive where quality and/or standards are important", "value": 1}, {"id": "c_trait_1", "label": "Analytical", "value": 1}, {"id": "c_trait_2", "label": "Contemplative", "value": 1}, {"id": "c_trait_3", "label": "Conservative", "value": 1}, {"id": "c_trait_4", "label": "Exacting", "value": 1}, {"id": "c_trait_5", "label": "Careful", "value": 1}, {"id": "c_trait_6", "label": "Deliberate", "value": 1}, {"id": "c_trait_7", "label": "I like to organize and analyze", "value": 1}, {"id": "c_trait_8", "label": "I work well alone", "value": 1}, {"id": "c_trait_9", "label": "I have high expectations", "value": 1}, {"id": "c_trait_10", "label": "I like to follow rules", "value": 1}, {"id": "c_trait_11", "label": "I am self-competitive", "value": 1}, {"id": "c_trait_12", "label": "I can solve complex problems", "value": 1}, {"id": "c_trait_13", "label": "I live my life by rules of behaving", "value": 1}, {"id": "c_trait_14", "label": "I tend to want as much data as possible", "value": 1}, {"id": "c_trait_15", "label": "I tend to be hard on myself", "value": 1}, {"id": "c_trait_16", "label": "I never take unnecessary chances", "value": 1}, {"id": "c_trait_17", "label": "I tend to feel emotions are very irrational", "value": 1}, {"id": "c_trait_18", "label": "I tend to see faults in others", "value": 1}, {"id": "c_trait_19", "label": "I tend to analyze things to death", "value": 1}], "allow_multiple": true}$json$::jsonb,
    6,
    true,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'my-core-style',
    'My Core Style — People Reading',
    'text',
    $json${"prompt": "Based on the D.I.S.C. exercise above, what is your Core Style? Use the two-question method to confirm: (1) Am I predominantly EXTROVERTED or INTROVERTED? (2) Am I predominantly PEOPLE-ORIENTED or TASK-ORIENTED?\n\nExtroverted + Task-Oriented = Core D | Extroverted + People-Oriented = Core I | Introverted + People-Oriented = Core S | Introverted + Task-Oriented = Core C\n\nWrite your Core Style and reflect on how it shows up in your daily life:", "placeholder": "My Core Style is ___ because...", "min_length": 10, "max_length": 2000}$json$::jsonb,
    7,
    false,
    NULL
