-- attitude
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='attitude')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'attitudes-introduction',
    'What Is an Attitude?',
    'info',
    $json${"content": "In 1928, Eduard Spranger wrote and published The Types of Men. Spranger observed that all people view the world differently. Whenever several people viewed the same object or event, they invariably placed different values upon it. Through his research, Spranger identified 6 world views that affect the values people place upon objects or events. He labelled these views as Attitudes.\n\nAn attitude is:\n1. A world view — a way of looking at life\n2. A paradigm of thought\n3. A value or judgment of life\n4. A mindset\n\nSpranger noted that:\n• VALUES AND ATTITUDES → create → WANTS\n• WANTS → determine → BEHAVIOUR\n• BEHAVIOUR → achieves → RESULTS\n\nWe all see the world through our own attitude-tinted eyes. And we either reject or value various aspects of life based upon our attitude towards them. According to Spranger, there is no such thing as a 'good' or 'bad' attitude.", "attribution": "(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)"}$json$::jsonb,
    1,
    false,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'identifying-attitudes',
    'EXERCISE: Identifying Your Attitudes',
    'checkbox',
    $json${"prompt": "From the following list of likes and dislikes, select those that most accurately describe who you are. The first answer that comes to your mind is usually a good indication of how you truly feel.\n\nGroup W (Theoretical — Questions 1–9):\nGroup A (Aesthetic — Questions 10–18):\nGroup T (Traditional — Questions 19–25):\nGroup U (Utilitarian — Questions 26–35):\nGroup S (Social — Questions 36–42):\nGroup I (Individualistic — Questions 43–50):\n\nCheck all that apply, then count your totals per group to find your top two attitudes.", "options": [{"id": "w_1", "label": "I like solving problems.", "value": 1}, {"id": "w_2", "label": "I like objectivity in all areas of life.", "value": 1}, {"id": "w_3", "label": "I like identifying, differentiating, generalizing, systematizing.", "value": 1}, {"id": "w_4", "label": "I like intellectual process.", "value": 1}, {"id": "w_5", "label": "I like discovery, understanding, ordering.", "value": 1}, {"id": "w_6", "label": "I like pursuit of knowledge, identifying truth and untruth.", "value": 1}, {"id": "w_7", "label": "I like knowledge for the sake of knowing.", "value": 1}, {"id": "w_8", "label": "I hate inability to know, learn or discover.", "value": 1}, {"id": "w_9", "label": "I hate emotional, subjective experience without rational justification.", "value": 1}, {"id": "a_10", "label": "I like appreciation of form, harmony and beauty.", "value": 1}, {"id": "a_11", "label": "I like enjoyment of all the senses.", "value": 1}, {"id": "a_12", "label": "I like subjective experience.", "value": 1}, {"id": "a_13", "label": "I like understanding the feelings of myself and others.", "value": 1}, {"id": "a_14", "label": "I like self-realization, self-fulfilment and self-actualization.", "value": 1}, {"id": "a_15", "label": "I like creative expression.", "value": 1}, {"id": "a_16", "label": "I like appreciation of impressions.", "value": 1}, {"id": "a_17", "label": "I hate disturbances in form, beauty and harmony in myself, others and/or the environment.", "value": 1}, {"id": "a_18", "label": "I object to objective truth.", "value": 1}, {"id": "t_19", "label": "I like understanding the totality of life.", "value": 1}, {"id": "t_20", "label": "I like finding meaning in life.", "value": 1}, {"id": "t_21", "label": "I like pursuit of the divine in life.", "value": 1}, {"id": "t_22", "label": "I like following and dying for a cause.", "value": 1}, {"id": "t_23", "label": "I like living constantly according to a 'closed' book.", "value": 1}, {"id": "t_24", "label": "I like converting others to my way of thinking.", "value": 1}, {"id": "t_25", "label": "I don't like people who oppose my beliefs.", "value": 1}, {"id": "u_26", "label": "I like practicality in all areas of my life.", "value": 1}, {"id": "u_27", "label": "I like surpassing others in the attainment of wealth.", "value": 1}, {"id": "u_28", "label": "I like using resources to accomplish results.", "value": 1}, {"id": "u_29", "label": "I like gaining a measurable return on all my investments.", "value": 1}, {"id": "u_30", "label": "I like creative application of resources.", "value": 1}, {"id": "u_31", "label": "I like producing goods, materials, services and marketing them for economic gain.", "value": 1}, {"id": "u_32", "label": "I like capitalism.", "value": 1}, {"id": "u_33", "label": "I like maximizing or conserving resources.", "value": 1}, {"id": "u_34", "label": "I don't like to see wasted resources, time, materials and/or services.", "value": 1}, {"id": "u_35", "label": "I hate investments with inadequate or no return.", "value": 1}, {"id": "s_36", "label": "I like investing in others.", "value": 1}, {"id": "s_37", "label": "I like selflessness.", "value": 1}, {"id": "s_38", "label": "I like generosity of time, talent and resources.", "value": 1}, {"id": "s_39", "label": "I like seeing and developing potential in others.", "value": 1}, {"id": "s_40", "label": "I like championing a worthy cause.", "value": 1}, {"id": "s_41", "label": "I don't like rampant individualism.", "value": 1}, {"id": "s_42", "label": "I hate decisions and actions which are insensitive to people's needs.", "value": 1}, {"id": "i_43", "label": "I like leading others.", "value": 1}, {"id": "i_44", "label": "I like achieving position.", "value": 1}, {"id": "i_45", "label": "I like advancing position and strategic alliances.", "value": 1}, {"id": "i_46", "label": "I like attaining and using power to accomplish purpose.", "value": 1}, {"id": "i_47", "label": "I like planning and carrying out a winning strategy.", "value": 1}, {"id": "i_48", "label": "I like tactics and positioning.", "value": 1}, {"id": "i_49", "label": "I hate actual or perceived threat of diminished power or position.", "value": 1}, {"id": "i_50", "label": "I hate inability to advance, lack of opportunity for individual advancement.", "value": 1}], "allow_multiple": true}$json$::jsonb,
    2,
    true,
    '(Adapted with permission from How To Read and Understand People Copyright 1988 Target Training International)'
  ),
  (
    (SELECT id FROM s),
    'attitude-types-watusi',
    'The Six Attitude Types — WATUSI',
    'ranking',
    $json${"prompt": "Your prefilled order below is derived from the checklist you just completed. The count beside each item is auto-calculated and read-only.", "interaction": "drag", "show_counts": true, "derives_from": {"source_exercise_slug": "identifying-attitudes", "group_by": "id_prefix"}, "items": [{"id": "attitude_w", "label": "W — The Theoretical Attitude: I use my intellect to systematically understand and discover the truth. The discovery of Truth and Knowledge is my main motivation in life. I seek knowledge for its own sake."}, {"id": "attitude_a", "label": "A — The Aesthetic Attitude: I enjoy and experience the beauty around me and find meaning and fulfilment within the experience of living. My main motivation is to experience the Inner Vision."}, {"id": "attitude_t", "label": "T — The Traditional Attitude: I pursue and understand the highest meaning of life within an established system of beliefs. My main motivation is to search and find the highest value in life."}, {"id": "attitude_u", "label": "U — The Utilitarian Attitude: I see most things in terms of their usefulness and practicality. My main motivation is to turn what I do and have into a useful purpose."}, {"id": "attitude_s", "label": "S — The Social Attitude: I enjoy helping others and believe that all decisions should be sensitive to people's needs. My main goal in life is to do what I can to eliminate hate and conflict in the world."}, {"id": "attitude_i", "label": "I — The Individualistic Attitude: I want to achieve the highest position possible and wield the greatest power in my chosen field and will do everything within my ability to reach these goals."}]}$json$::jsonb,
    3,
    true,
    NULL
  ),
  (
    (SELECT id FROM s),
    'attitude-power-points',
    'EXERCISE: Attitude Power Points — Reflection',
    'text',
    $json${"prompt": "Reflect on the following Attitude Power Points and write how your top two attitudes show up in your daily life, career choices, and relationships:\n\n1. An attitude is a way of valuing life — a world view, a paradigm of thought and action.\n2. Most of a person's choices throughout life are guided by the hierarchy of their attitudes and needs satisfactions.\n3. Attitudes determine our purpose and direction in life, stimulating us to action.\n4. Attitudes are relatively constant throughout life and will usually change only in relation to a Significant Emotional Event.\n5. Behaviour (D.I.S.C.) is the methodology for fulfilling the passions driven by our attitudes.\n6. Attitudes tend to interact with one another.\n\nHow do your top two attitude types interact? Do they support or conflict with each other?", "placeholder": "My top two attitudes are ___ and ___. I notice them showing up in my life when...", "min_length": 50, "max_length": 2000}$json$::jsonb,
    4,
    false,
    NULL
  );

-- values
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='values')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'values-shopping-spree',
    'EXERCISE: Values Shopping Spree',
    'table',
    $json${"prompt": "CONGRATULATIONS! You have won an imaginary $100,000! But there's a catch — you have to spend it all in the PSP™ Value Boutique. Read through the complete list carefully, then allocate dollar amounts to the items that are important to you. You MUST spend all of the $100,000 — no more, no less.\n\nGuidelines:\n• Buy only those things most important to YOU — not what others say should be important.\n• Pretend you are starting with nothing.\n• Do not let parents, priests, friends or teachers influence your purchases.\n• Read through the ENTIRE list before purchasing.", "headers": ["#", "Item", "Amount Budgeted ($)"], "rows": 34, "col_types": ["number", "text", "currency"], "total_target": 100000, "items": ["A process guaranteed to rid the world of prejudice and racism.", "An opportunity to help the sick and impoverished and allow them happier lives.", "The charisma and resources necessary to become famous (movie star, sports hero, astronaut, author).", "The chance to create and implement a sure-fire money-making idea.", "A morning massage everyday and breakfast, lunch and dinner cooked by a world class chef.", "Absolute enlightenment and understanding of myself.", "Consistency throughout my life between thought, word and deed.", "The opportunity to be my own boss.", "As much money as Bill Gates (even more).", "To be President of The World.", "The perfect relationship.", "My dream house with a breath-taking view, filled with my favorite things.", "To be one of the most attractive people in the world.", "To be perfectly healthy.", "Peace of mind.", "My own library filled with every publication I ever wanted to read.", "Absolute union with the Almighty in thought and deed.", "A world of equal justice and opportunity for everyone.", "Enough money to fund an organization that truly helps everyone.", "To win the Nobel Prize in my chosen field, and be praised everywhere in the world.", "To master every skill needed to be the best in my job.", "A genie at my beck and call, with unlimited power to satisfy my every wish so I can enjoy life to the fullest.", "To be the wisest person ever to live.", "A bottle of 'honesty gas' large enough to cure the whole world of lying.", "To be completely independent of anyone.", "To own a Texas oil well.", "To be a role model and guru to people throughout the world.", "To perfectly express my love and caring.", "A Super Pass that lets me into any concert, play, opera, art show or ballet and to travel anywhere I want by land, sea or air.", "A complete make-over: hair, clothes, manicure, plastic surgery, time at a spa, whatever I want in order to look my best.", "The perfect body.", "Absolute self-esteem and the confidence to think and say what I feel.", "To learn anything instantly and be able to recall it at a moment's notice.", "Uninterrupted conversations with any spiritual leader(s) I want, past or present."]}$json$::jsonb,
    1,
    true,
    NULL
  ),
  (
    (SELECT id FROM s),
    'what-do-i-value',
    'EXERCISE: What Do I Value?',
    'ranking',
    $json${"prompt": "After completing the Values Shopping Spree, add each pair of items to total the score for that value. Then rank the 17 values from highest to lowest total spending. Your top 3 are your core values.", "items": [{"id": "val_justice", "label": "Justice — Moral rightness, honor, fairness (Items 1 + 18)"}, {"id": "val_humanitarianism", "label": "Humanitarianism — Devotion to the promotion of human welfare (Items 2 + 19)"}, {"id": "val_recognition", "label": "Recognition — Acknowledgment of one's significance or importance (Items 3 + 20)"}, {"id": "val_achievement", "label": "Achievement — Accomplishment (Items 4 + 21)"}, {"id": "val_pleasure", "label": "Pleasure — Enjoyment, satisfaction, satiation (Items 5 + 22)"}, {"id": "val_wisdom", "label": "Wisdom — Understanding of what is true, right or lasting (Items 6 + 23)"}, {"id": "val_honesty", "label": "Honesty — Straightforwardness, integrity, consistency (Items 7 + 24)"}, {"id": "val_autonomy", "label": "Autonomy — Independence, self-containment (Items 8 + 25)"}, {"id": "val_economy", "label": "Economy — Abundance of material possessions, wealth (Items 9 + 26)"}, {"id": "val_power", "label": "Power — Control, authority or influence (Items 10 + 27)"}, {"id": "val_love", "label": "Love — Affection, warm attachment, caring (Items 11 + 28)"}, {"id": "val_aesthetics", "label": "Aesthetics — Appreciation and enjoyment of beauty for beauty's sake (Items 12 + 29)"}, {"id": "val_physical_attractiveness", "label": "Physical Attractiveness — Concern for the appearance of one's body (Items 13 + 30)"}, {"id": "val_health", "label": "Health — Concern for the health of one's body (Items 14 + 31)"}, {"id": "val_wellbeing", "label": "Feeling of Well-Being — Freedom from anxiety, imbalance; peace of mind (Items 15 + 32)"}, {"id": "val_knowledge", "label": "Knowledge — Seeking of truth and/or information (Items 16 + 33)"}, {"id": "val_spiritual", "label": "Spiritual Well-Being — Communion with, obedience to, and activity on behalf of a Supreme Being (Items 17 + 34)"}]}$json$::jsonb,
    2,
    true,
    NULL
  ),
  (
    (SELECT id FROM s),
    'top-three-values',
    'My Top Three Values',
    'structured-text',
    $json${"intro": "Based on the Values Shopping Spree exercise, list your top three values (those you spent the most money on) and reflect on how each one shows up as a driving force in your life. How do these values influence your career choices, relationships, and daily decisions?", "questions": [{"id": "top_1", "prompt": "My #1 top value is ___ — describe how it shows up as a driving force in your life, career, and relationships.", "required": true, "max_length": 800, "min_length": 30}, {"id": "top_2", "prompt": "My #2 top value is ___ — describe how it shows up as a driving force in your life, career, and relationships.", "required": true, "max_length": 800, "min_length": 30}, {"id": "top_3", "prompt": "My #3 top value is ___ — describe how it shows up as a driving force in your life, career, and relationships.", "required": true, "max_length": 800, "min_length": 30}]}$json$::jsonb,
    3,
    false,
    NULL
  );

-- roles-and-demands
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='roles-and-demands')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'life-line-exercise',
    'EXERCISE: My Life Line — Past, Present and Future',
    'text',
    $json${"prompt": "Draw a line (in your workbook or mind) that depicts your life as you see it from beginning to end. Your lifeline may be any shape and go in any direction — a road, river, thread, path, or graph line. Place three marks indicating your birth, your death, and where you are now.\n\nOnce you have reflected on your lifeline, write your observations below:\n\nTHE PAST (your unique experiences, acquired skills, and personal history):\n• The past has happened; we cannot change it.\n• Your past has a place in your current life — accept it, reconstruct it, evaluate it creatively.\n• The past can yield insight into your unfulfilled potential.\n\nTHE PRESENT (the here and now with all its joys, frustrations, priorities and demands):\n• You can choose where you want to go based on what satisfies you now.\n• You have undeveloped potential that suggests directions for future development.\n\nTHE FUTURE (your aspirations, dreams, goals, hopes and fears):\n• To a large degree, you create your own future.\n• All three perspectives are necessary to develop a more fulfilling life plan.\n\nWhat themes do you notice across your past, present, and future?", "placeholder": "Looking at my lifeline, I notice...\n\nIn my PAST, the most significant experiences were...\n\nIn my PRESENT, I am...\n\nFor my FUTURE, I hope/fear...", "min_length": 50, "max_length": 3000}$json$::jsonb,
    1,
    false,
    NULL
  ),
  (
    (SELECT id FROM s),
    'who-am-i-now',
    'EXERCISE: Who Am I Now?',
    'table',
    $json${"prompt": "Write 10 separate short statements that answer the question 'Who am I?' Then rank these statements according to their importance to YOU — not how you think others would rank them. Ensure that at least 3–4 of your roles are defined in view of your responsibilities or accountabilities to specific individuals or groups (family, children, spouses, etc.).", "headers": ["Rank Order", "Who Am I? (complete the sentence: I am...)"], "rows": 10, "col_types": ["number", "text"]}$json$::jsonb,
    2,
    false,
    NULL
  ),
  (
    (SELECT id FROM s),
    'past-experience-inventory',
    'EXERCISE: Past Experience Inventory',
    'structured-text',
    $json${"questions": [{"id": "q1", "min_length": 20, "max_length": 800, "prompt": "Who have been the most influential people in your life and in what way?", "required": true}, {"id": "q2", "min_length": 20, "max_length": 800, "prompt": "What were the critical incidents (events) that made you who you are?", "required": true}, {"id": "q3", "min_length": 20, "max_length": 800, "prompt": "What have been the major interests in your life so far?", "required": true}, {"id": "q4", "min_length": 20, "max_length": 800, "prompt": "What were the significant experiences in your school or college career?", "required": true}, {"id": "q5", "min_length": 20, "max_length": 800, "prompt": "What were your significant work experiences?", "required": true}, {"id": "q6", "min_length": 20, "max_length": 800, "prompt": "What were the most significant decisions in your life?", "required": true}, {"id": "q7", "min_length": 20, "max_length": 800, "prompt": "What makes you alive and excited? What events or activities spur you on?", "required": true}, {"id": "q8", "min_length": 20, "max_length": 800, "prompt": "What am I really good at? What strengths do I have to build on?", "required": true}, {"id": "q9", "min_length": 20, "max_length": 800, "prompt": "What do I do poorly? What do I need to develop or correct?", "required": true}, {"id": "q10", "min_length": 20, "max_length": 800, "prompt": "What do I want to stop doing that affects my effectiveness?", "required": true}, {"id": "q11", "min_length": 20, "max_length": 800, "prompt": "What do I want to change in my life?", "required": true}, {"id": "q12", "min_length": 20, "max_length": 800, "prompt": "What do I want to start doing much better?", "required": true}, {"id": "q13", "min_length": 20, "max_length": 800, "prompt": "What do I want to learn or develop in myself?", "required": true}, {"id": "q14", "min_length": 20, "max_length": 800, "prompt": "Who are the persons or organizations that can help me achieve my goals?", "required": true}], "intro": "Answer each of the following 14 questions as honestly and fully as possible. This inventory helps you identify the experiences, influences, and patterns that have shaped who you are today."}$json$::jsonb,
    3,
    false,
    NULL
  ),
  (
    (SELECT id FROM s),
    'contract-with-myself',
    'EXERCISE: A Contract With Myself',
    'structured-text',
    $json${"questions": [{"id": "article_1", "min_length": 15, "max_length": 600, "prompt": "Article 1 — What do I want to change in my life for the better?", "required": true}, {"id": "article_2", "min_length": 15, "max_length": 600, "prompt": "Article 2 — What do I need to get what I want?", "required": true}, {"id": "article_3", "min_length": 15, "max_length": 600, "prompt": "Article 3 — What am I willing to do?", "required": true}, {"id": "article_4", "min_length": 15, "max_length": 600, "prompt": "Article 4 — How will I measure my success?", "required": true}, {"id": "article_5", "min_length": 15, "max_length": 600, "prompt": "Article 5 — How could I sabotage myself from achieving success?", "required": true}, {"id": "article_6", "min_length": 15, "max_length": 600, "prompt": "Article 6 — What are my next positive steps toward change?", "required": true}], "intro": "Complete this personal contract for change (as suggested by Professor Muriel James, author of Born to Win):"}$json$::jsonb,
    4,
    false,
    '(From Professor Muriel James, author of Born to Win, Breaking Free, Passion for Life — on transactional analysis)'
  ),
  (
    (SELECT id FROM s),
    'mission-statement',
    'EXERCISE: My Mission Statement',
    'structured-text',
    $json${"questions": [{"id": "vision", "min_length": 15, "max_length": 600, "prompt": "My Vision / Mission / Purpose for this life is...", "required": true}, {"id": "self", "min_length": 15, "max_length": 600, "prompt": "In relation to MYSELF...", "required": true}, {"id": "others", "min_length": 15, "max_length": 600, "prompt": "In relation to OTHERS...", "required": true}, {"id": "world", "min_length": 15, "max_length": 600, "prompt": "In relation to THE WORLD...", "required": true}, {"id": "one_sentence", "min_length": 10, "max_length": 300, "prompt": "If I put it in one sentence, my mission is...", "required": true}], "intro": "A Mission/Vision Statement gives you a powerful tool to help you focus and prioritize your life. Tip: look at your own eyes in the mirror and repeat each line back to yourself. Does it fit you completely?"}$json$::jsonb,
    5,
    false,
    NULL
  );

-- transferable-skills
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='transferable-skills')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'transferable-skills-with-individuals',
    'EXERCISE: Transferable Skills — Dealing with Individuals',
    'rating-picker',
    $json${"prompt": "Rate each skill on a scale of 1 (lowest) to 5 (highest). These are skills you use when dealing with individuals one-on-one.", "scale": {"min": 1, "max": 5, "labels": ["Strongly Disagree", "Disagree", "Neutral", "Agree", "Strongly Agree"]}, "items": [{"id": "ind_1", "label": "Take instructions, Serve or Help"}, {"id": "ind_2", "label": "Diagnose, Treat or Heal"}, {"id": "ind_3", "label": "Do well in conversation, in person, or on the phone"}, {"id": "ind_4", "label": "Refer people, or help two to link up"}, {"id": "ind_5", "label": "Communicate well in writing (e.g. excellent letters)"}, {"id": "ind_6", "label": "Assess, Evaluate, Screen, or Select Individuals"}, {"id": "ind_7", "label": "Instruct, Teach, Tutor, or Train Individuals"}, {"id": "ind_8", "label": "Persuade, Motivate, Recruit, Sell to Individuals"}, {"id": "ind_9", "label": "Advise, Coach, Counsel, Mentor"}, {"id": "ind_10", "label": "Represent Others, Interpret Others' Ideas"}]}$json$::jsonb,
    1,
    true,
    NULL
  ),
  (
    (SELECT id FROM s),
    'transferable-skills-with-groups',
    'EXERCISE: Transferable Skills — Dealing with Groups',
    'rating-picker',
    $json${"prompt": "Rate each skill on a scale of 1 (lowest) to 5 (highest). These are skills you use when working with groups and audiences.", "scale": {"min": 1, "max": 5, "labels": ["Strongly Disagree", "Disagree", "Neutral", "Agree", "Strongly Agree"]}, "items": [{"id": "grp_1", "label": "Communicate Effectively to a group or a multitude"}, {"id": "grp_2", "label": "Play games or lead others in recreation"}, {"id": "grp_3", "label": "Manage, Supervise or Run (a business, fund drive etc.)"}, {"id": "grp_4", "label": "Use words expressively in speaking or writing"}, {"id": "grp_5", "label": "Teach, Train, or Design educational events"}, {"id": "grp_6", "label": "Follow through getting things done"}, {"id": "grp_7", "label": "Make presentations in person, or on TV or film"}, {"id": "grp_8", "label": "Guide a Group Discussion conveying warmth"}, {"id": "grp_9", "label": "Take the lead, be a pioneer"}, {"id": "grp_10", "label": "Perform, Entertain, Amuse or Inspire"}, {"id": "grp_11", "label": "Persuade a Group, Motivate or Sell"}, {"id": "grp_12", "label": "Initiating, Starting Up, Founding, Or Establishing"}, {"id": "grp_13", "label": "Sign, Mimic, Act, Sing, or Play an Instrument"}, {"id": "grp_14", "label": "Consult, give advice to groups in your area of service"}, {"id": "grp_15", "label": "Negotiate between two parties, or resolve conflict"}]}$json$::jsonb,
    2,
    true,
    NULL
  ),
  (
    (SELECT id FROM s),
    'transferable-skills-information',
    'EXERCISE: Transferable Skills — Dealing with Information & Data',
    'rating-picker',
    $json${"prompt": "Rate each skill on a scale of 1 (lowest) to 5 (highest). These are skills you use when gathering, managing, storing and retrieving information, data, and ideas.", "scale": {"min": 1, "max": 5, "labels": ["Strongly Disagree", "Disagree", "Neutral", "Agree", "Strongly Agree"]}, "items": [{"id": "inf_1", "label": "Compile, Search, or Research"}, {"id": "inf_2", "label": "Gather information by interviewing or observing people"}, {"id": "inf_3", "label": "Gather information by studying or observing things"}, {"id": "inf_4", "label": "Have an acute sense of hearing, smell, taste, or sight"}, {"id": "inf_5", "label": "Imagine, invent, create or design new ideas"}, {"id": "inf_6", "label": "Copy and/or compare similarities or differences"}, {"id": "inf_7", "label": "Compute, working with numbers, do accounting"}, {"id": "inf_8", "label": "Analyze, break down into its parts"}, {"id": "inf_9", "label": "Organize, classify, systematize, and/or prioritize"}, {"id": "inf_10", "label": "Plan, lay out step by step process for achieving a goal"}, {"id": "inf_11", "label": "Adapt, translate (incl. computer programming), develop or improve"}, {"id": "inf_12", "label": "Visualize, draw, paint, dramatize, create videos or software"}, {"id": "inf_13", "label": "Synthesize, combining parts into a whole"}, {"id": "inf_14", "label": "Problem solve or see patterns among a mass of data"}, {"id": "inf_15", "label": "Decide, evaluate, appraise, or make recommendations"}, {"id": "inf_16", "label": "Keep Records (Incl. on film or on a computer)"}, {"id": "inf_17", "label": "Store or File: microfiche, video, audio, or computer"}, {"id": "inf_18", "label": "Retrieve information, ideas, data"}, {"id": "inf_19", "label": "Enable other people to find or retrieve information"}, {"id": "inf_20", "label": "Have a superior memory, keeping track of details"}]}$json$::jsonb,
    3,
    true,
    NULL
  ),
  (
    (SELECT id FROM s),
    'favorite-strongest-skills',
    'EXERCISE: My Favorite & Strongest Skills',
    'structured-text',
    $json${"intro": "List your top six favorite AND strongest skills. Remember — favorite AND strongest, not just strongest. Feel free to add any skills not found in the previous exercise. Your passions matter here as much as your proficiency.", "questions": [{"id": "skill_1", "prompt": "My favorite and strongest skill is:", "required": true, "max_length": 400, "min_length": 5}, {"id": "skill_2", "prompt": "My second favorite and strongest skill is:", "required": true, "max_length": 400, "min_length": 5}, {"id": "skill_3", "prompt": "My third favorite and strongest skill is:", "required": true, "max_length": 400, "min_length": 5}, {"id": "skill_4", "prompt": "My fourth favorite and strongest skill is:", "required": true, "max_length": 400, "min_length": 5}, {"id": "skill_5", "prompt": "My fifth favorite and strongest skill is:", "required": true, "max_length": 400, "min_length": 5}, {"id": "skill_6", "prompt": "My sixth favorite and strongest skill is:", "required": true, "max_length": 400, "min_length": 5}]}$json$::jsonb,
    4,
    false,
    NULL
  );

-- specific-goals
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='specific-goals')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'life-goal-inventory',
    'EXERCISE: My Life Goal Inventory',
    'table',
    $json${"prompt": "Describe your aims and goals for ALL areas of your life as fully as possible. Be as specific as you can — include the date by which you wish to have each goal achieved. Sift each goal through your four filters: Personal Style, Attitudes and Values, Roles and their Demands, and Transferable Skills.\n\nGoal Importance: H (High) = very important compared to others | M (Moderate) = moderately important | L (Low) = other goals are more important\n\nEase of Attainment: H (High) = easily reachable | M (Moderate) = reachable with moderate difficulty | L (Low) = very difficult to reach\n\nCategories:\nA — Career Satisfaction: your goals for your future job or career, including specific positions you want to hold.\nB — Status and Respect: how important is receiving respect from others? From whom? What groups do you belong to?\nC — Personal Relationships: goals in your relationships with colleagues, parents, friends, people in general.\nD — Learning and Education: what would you like to know more about? What skills do you want to develop?\nE — Material Rewards and Possessions: what kind of wealth is important to you? What possessions would you want?\nF — Leisure Satisfaction: goals for leisure time — hobbies, sports, vacations, interests you want to develop.\nG — Spiritual Growth and Religion: goals for peace of mind, your search for meaning — relationship to nature, community, devotional life, meditation.\nH — Open: goals that don't fit the above categories.", "headers": ["Category", "Specific Goal", "Importance (H/M/L)", "Ease of Attainment (H/M/L)", "Conflict with Other Goals (Yes/No)"], "rows": 24, "col_types": ["text", "text", "text", "text", "text"]}$json$::jsonb,
    1,
    false,
    '(Adapted with kind permission from Dr. David Kolb. From Organizational Behavior: An Experiential Approach, Fifth Edition — David Kolb, Irwin M. Rubin and Joyce Osland. Prentice Hall, Englewood Cliffs, N.Y. 07632.)'
  ),
  (
    (SELECT id FROM s),
    'goal-priorities',
    'Goal Priorities — My Top 10',
    'ranking',
    $json${"prompt": "From all the goals in your Life Goal Inventory, select the ones that seem most important to you at this time. Do not choose more than ten (10). Drag the rows to order them — most important first, least important last.", "interaction": "drag", "items": [{"id": "priority_1", "label": "Goal Priority 1 (Most Important)"}, {"id": "priority_2", "label": "Goal Priority 2"}, {"id": "priority_3", "label": "Goal Priority 3"}, {"id": "priority_4", "label": "Goal Priority 4"}, {"id": "priority_5", "label": "Goal Priority 5"}, {"id": "priority_6", "label": "Goal Priority 6"}, {"id": "priority_7", "label": "Goal Priority 7"}, {"id": "priority_8", "label": "Goal Priority 8"}, {"id": "priority_9", "label": "Goal Priority 9"}, {"id": "priority_10", "label": "Goal Priority 10 (Least Important of Top 10)"}]}$json$::jsonb,
    2,
    false,
    NULL
  );

-- goal-impact-matrix
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='goal-impact-matrix')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'cross-impact-matrix',
    'EXERCISE: The Cross-Impact Matrix',
    'table',
    $json${"prompt": "One of the major blocks to goal accomplishment is the conflict between goals. Take your top 8 goals and enter them across the top and down the left-hand side. Then use the following symbols to rank the effect each goal has on the others:\n\n+ = helpful impact (working on Goal 1 will HELP me with Goal 3)\n- = hindering impact (working on Goal 2 will make it MORE DIFFICULT to accomplish Goal 5)\n0 = no impact of any kind\n\nNote: Where a goal meets itself, mark 0 (obviously Goal 1 has no impact where it meets Goal 1).\n\nAfter completing the matrix, list at least five conflicts in order of importance.", "headers": ["", "Goal 1", "Goal 2", "Goal 3", "Goal 4", "Goal 5", "Goal 6", "Goal 7", "Goal 8"], "rows": 8, "col_types": ["text", "text", "text", "text", "text", "text", "text", "text", "text"]}$json$::jsonb,
    1,
    false,
    NULL
  );

-- visualization
WITH s AS (SELECT id, slug FROM public.sections WHERE slug='visualization')
INSERT INTO public.exercises (section_id, slug, title, type, content_json, order_index, is_scored, attribution) VALUES
  (
    (SELECT id FROM s),
    'visualization-practice',
    'The Importance of Visualization',
    'info',
    $json${"content": "Research has shown that every thought we think has an affect on the chemistry of our bodies. By visualizing goal attainment, we actually increase our motivation to achieve them.\n\n**The next exercise will show you how visualization will help you in achieving your goals:**\n\n- Stand up.\n- Take a deep breath and let it out slowly.\n- Repeat two or three times. If you know other body relaxation exercises, do them now.\n- Once you are relaxed, close your eyes, get comfortable, and go to a place called the \"hallways of your mind\". This is a limitless place with an infinite number of rooms and spaces. Can you see it? Find the place that has to do with achieving all 8 of your goals.\n- Visualize yourself having achieved all 8 of these goals.\n- Take note of your posture in this situation. Note your breathing pattern and how your muscles feel. Are they tense, relaxed, alert?\n- Take note if there is anyone else with you in this place. Who are they? What are their posture and facial expressions? How are they relating to you?\n- Note everything around you in this place, including colours, sounds, textures, smells and tastes. Recognize that you can go to this place any time. And that you can change anything at any time.\n- Now take a deep breath and blow it out as if you were blowing out a candle.\n- Open your eyes and take a moment to reorientate yourself to where you are.\n\nDo this exercise at least once a day, twice if you can. The best times are in the morning when you first wake up and at night as you're dozing off to sleep. Go to this place any time you are under stress or have lost track of where you're going and what you are doing in your life. Some find it helpful to use a picture that represents their future achievements. Whether you buy one or draw one yourself, a concrete visual representation can be very powerful."}$json$::jsonb,
    1,
    false,
    'Personal Strategic Planning™ — © Sam Koshy / Compass Career Life Solutions, Canada.'
  ),
  (
    (SELECT id FROM s),
    'visualization-journal',
    'Visualization Journal',
    'structured-text',
    $json${"intro": "After completing the visualization practice above, record what you experienced. Return to this journal each time you repeat the practice — your answers will deepen and shift over the weeks ahead.", "questions": [{"id": "what_seen", "prompt": "What did you see in the place that has to do with achieving all 8 of your goals? Describe the scene as vividly as you can.", "required": true, "max_length": 1500, "min_length": 20}, {"id": "who_present", "prompt": "Who else was with you in this place? What were their posture and facial expressions, and how were they relating to you?", "required": true, "max_length": 1200, "min_length": 20}, {"id": "place_details", "prompt": "Note everything around you — colours, sounds, textures, smells, tastes. What stood out?", "required": true, "max_length": 1200, "min_length": 20}, {"id": "one_action", "prompt": "Name one concrete action you can take this week, drawn from what you saw, that moves you closer to your future self.", "required": true, "max_length": 800, "min_length": 20}]}$json$::jsonb,
    2,
    false,
    'Personal Strategic Planning™ — © Sam Koshy / Compass Career Life Solutions, Canada.'
  );

-- removing-obstacles-achieving-goals
